/**
 * MMS PM Management Tables
 *
 * Preventive maintenance scheduling: PM types, material requirements, and schedules.
 * Core tables for the maintenance planning workflow.
 *
 * PM Hierarchy: Higher-level PMs satisfy lower-level requirements
 * - C4 satisfies C1, C2, C3 (resets their counters)
 * - Overhaul satisfies all PM types
 *
 * @see specs/003-database-schema.md Sections 3.5
 */

import { relations, sql } from 'drizzle-orm';
import {
  boolean,
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots, fleets, tracks, trains } from './core-fleet';
import { materialCriticalityEnum, pmStatusEnum, shiftTypeEnum, trackTypeEnum } from './enums';
import { users } from './users';

/**
 * PM Types - Maintenance task definitions
 *
 * Defines the maintenance tasks for each fleet with their intervals
 * and resource requirements.
 *
 * Key concepts:
 * - interval_km / interval_months: Whichever triggers first
 * - satisfies_codes: PM hierarchy (C4 satisfies C1/C2/C3)
 * - early/late tolerance: Compliance window (default ±10%)
 *
 * Version management: PM intervals can change over the 12-year contract.
 * The effective_from/effective_to fields support versioning.
 */
export const pmTypes = pgTable(
  'pm_types',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    fleetId: uuid('fleet_id')
      .notNull()
      .references(() => fleets.id),
    pmCode: varchar('pm_code', { length: 20 }).notNull(), // 'C1', 'C2', 'C3', 'C4', 'OVERHAUL'
    pmName: varchar('pm_name', { length: 100 }).notNull(),
    version: integer('version').default(1),

    // Interval thresholds (whichever comes first)
    intervalKm: integer('interval_km'),
    intervalMonths: integer('interval_months'),

    // PM Hierarchy: which lower-level PMs does this PM satisfy?
    // When a C4 is completed, it satisfies C1/C2/C3 requirements
    // Example: C4 row has satisfies_codes = ['C1', 'C2', 'C3']
    satisfiesCodes: text('satisfies_codes').array(),

    // Resource requirements
    estimatedHours: decimal('estimated_hours', { precision: 6, scale: 2 }).notNull(),
    trackType: trackTypeEnum('track_type').notNull(),
    minTrackDays: integer('min_track_days').default(1), // How many days track is occupied

    // Compliance window tolerance (percentage)
    earlyTolerancePct: decimal('early_tolerance_pct', { precision: 5, scale: 2 }).default('10.0'),
    lateTolerancePct: decimal('late_tolerance_pct', { precision: 5, scale: 2 }).default('10.0'),

    // Certification requirements
    requiredCertifications: text('required_certifications').array(),

    // v2.1: PM type versioning for interval changes over contract life
    effectiveFrom: date('effective_from').notNull().default(sql`CURRENT_DATE`),
    effectiveTo: date('effective_to'), // NULL = current version
    supersededBy: uuid('superseded_by'), // Link to newer version

    // Canvas display properties
    displayColor: varchar('display_color', { length: 7 }),
    displayPriority: integer('display_priority').default(50),

    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_pm_types_unique').on(table.fleetId, table.pmCode, table.version),
    index('idx_pm_types_current').on(table.fleetId, table.pmCode, table.effectiveFrom),
  ]
);

/**
 * PM Material Requirements - Bill of Materials
 *
 * Links PM types to required parts with quantities and criticality.
 *
 * Criticality levels determine scheduling constraints:
 * - BLOCKING: Cannot start PM without part (14-day hard constraint)
 * - DEFERRABLE: Can start, must have within X days
 * - CONSUMABLE: Nice-to-have, can substitute
 */
export const pmMaterialRequirements = pgTable(
  'pm_material_requirements',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),
    partNumber: varchar('part_number', { length: 50 }).notNull(),
    partDescription: text('part_description'),

    quantityPerPm: integer('quantity_per_pm').notNull().default(1),
    criticality: materialCriticalityEnum('criticality').notNull().default('BLOCKING'),

    leadTimeDays: integer('lead_time_days').default(14),
    substituteParts: text('substitute_parts').array(), // Alternative part numbers

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_pm_materials_unique').on(table.pmTypeId, table.partNumber),
    index('idx_pm_materials_type').on(table.pmTypeId),
  ]
);

/**
 * PM Schedule - Planned and executed maintenance
 *
 * The core scheduling table. Each row represents a planned or completed PM.
 *
 * Key fields:
 * - constraint_start/end: Compliance window (calculated from PM type tolerances)
 * - is_locked: When true, optimizer cannot move this PM
 * - maximo_wo_id: Link to Maximo work order (when INPRG, PM is locked)
 * - scenario_id: NULL for production, non-NULL for what-if scenarios
 *
 * Status transitions:
 * SCHEDULED -> IN_PROGRESS -> COMPLETED
 * SCHEDULED -> DEFERRED -> SCHEDULED (new date)
 * SCHEDULED -> CANCELLED
 */
export const pmSchedule = pgTable(
  'pm_schedule',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),

    // Scheduling
    targetDate: date('target_date').notNull(),
    targetMileageKm: integer('target_mileage_km'),
    status: pmStatusEnum('status').default('SCHEDULED'),

    // Compliance window
    constraintStart: date('constraint_start').notNull(), // Earliest allowed date
    constraintEnd: date('constraint_end').notNull(), // Latest allowed date

    // Resource assignment
    assignedDepotId: uuid('assigned_depot_id').references(() => depots.id),
    assignedTrackId: uuid('assigned_track_id').references(() => tracks.id),
    assignedHours: decimal('assigned_hours', { precision: 6, scale: 2 }),
    assignedShift: shiftTypeEnum('assigned_shift'),

    // Execution
    actualStartDate: date('actual_start_date'),
    actualEndDate: date('actual_end_date'),
    actualHours: decimal('actual_hours', { precision: 6, scale: 2 }),
    completedAt: timestamp('completed_at', { withTimezone: true }),
    completedMileageKm: integer('completed_mileage_km'),

    // Work order integration (Maximo)
    maximoWoId: varchar('maximo_wo_id', { length: 50 }),

    // Locking - prevents optimizer from moving
    isLocked: boolean('is_locked').default(false),
    lockedReason: varchar('locked_reason', { length: 100 }),
    lockedBy: uuid('locked_by').references(() => users.id),
    lockedAt: timestamp('locked_at', { withTimezone: true }),

    // Scenario support (NULL = production schedule)
    scenarioId: uuid('scenario_id'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
    createdBy: uuid('created_by').references(() => users.id),
  },
  (table) => [
    index('idx_pm_schedule_train').on(table.trainId, table.targetDate),
    index('idx_pm_schedule_date').on(table.targetDate, table.status),
    index('idx_pm_schedule_depot').on(table.assignedDepotId, table.targetDate),
    index('idx_pm_schedule_scenario').on(table.scenarioId),
    index('idx_pm_schedule_canvas').on(table.targetDate, table.trainId),
    index('idx_pm_schedule_maximo').on(table.maximoWoId),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const pmTypesRelations = relations(pmTypes, ({ one, many }) => ({
  fleet: one(fleets, {
    fields: [pmTypes.fleetId],
    references: [fleets.id],
  }),
  materialRequirements: many(pmMaterialRequirements),
  schedules: many(pmSchedule),
}));

export const pmMaterialRequirementsRelations = relations(pmMaterialRequirements, ({ one }) => ({
  pmType: one(pmTypes, {
    fields: [pmMaterialRequirements.pmTypeId],
    references: [pmTypes.id],
  }),
}));

export const pmScheduleRelations = relations(pmSchedule, ({ one }) => ({
  train: one(trains, {
    fields: [pmSchedule.trainId],
    references: [trains.id],
  }),
  pmType: one(pmTypes, {
    fields: [pmSchedule.pmTypeId],
    references: [pmTypes.id],
  }),
  assignedDepot: one(depots, {
    fields: [pmSchedule.assignedDepotId],
    references: [depots.id],
  }),
  assignedTrack: one(tracks, {
    fields: [pmSchedule.assignedTrackId],
    references: [tracks.id],
  }),
  lockedByUser: one(users, {
    fields: [pmSchedule.lockedBy],
    references: [users.id],
    relationName: 'lockedBy',
  }),
  createdByUser: one(users, {
    fields: [pmSchedule.createdBy],
    references: [users.id],
    relationName: 'createdBy',
  }),
}));

