   568→  // ===========================================================================
   569→  // PM Hierarchy Handling
   570→  // ===========================================================================
   571→
   572→  /**
   573→   * Check if a higher-level PM has satisfied this PM type's requirement.
   574→   *
   575→   * PM Hierarchy: C4 satisfies C1/C2/C3, Overhaul satisfies all
   576→   */
   577→  private async checkHierarchySatisfaction(
   578→    trainId: string,
   579→    pmType: PmType,
   580→    sinceDate: Date | null
   581→  ): Promise<{ satisfiedBy: string | null; satisfiedByPm: PmScheduleRecord | null }> {
   582→    // Find PM types that satisfy this one
   583→    const satisfyingTypes = await this.db.query.pmTypes.findMany({
   584→      where: and(
   585→        eq(pmTypes.fleetId, pmType.fleetId),
   586→        eq(pmTypes.active, true),
   587→        sql`${pmType.pmCode} = ANY(${pmTypes.satisfiesCodes})`
   588→      ),
   589→    });
   590→
   591→    if (satisfyingTypes.length === 0) {
   592→      return { satisfiedBy: null, satisfiedByPm: null };
   593→    }
   594→
   595→    // Find the most recent completed PM of a satisfying type
   596→    const satisfyingTypeIds = satisfyingTypes.map(t => t.id);
   597→    const sinceDateFilter = sinceDate
   598→      ? gte(pmSchedule.completedAt, sinceDate)
   599→      : undefined;
   600→
   601→    const satisfyingPm = await this.db.query.pmSchedule.findFirst({
   602→      where: and(
   603→        eq(pmSchedule.trainId, trainId),
   604→        inArray(pmSchedule.pmTypeId, satisfyingTypeIds),
   605→        eq(pmSchedule.status, 'COMPLETED'),
   606→        isNull(pmSchedule.scenarioId),
   607→        sinceDateFilter
   608→      ),
   609→      orderBy: desc(pmSchedule.completedAt),
   610→    });
   611→
   612→    if (satisfyingPm) {
   613→      const satisfyingType = satisfyingTypes.find(t => t.id === satisfyingPm.pmTypeId);
   614→      return {
   615→        satisfiedBy: satisfyingType?.pmCode ?? null,
   616→        satisfiedByPm: satisfyingPm,
   617→      };
   618→    }
   619→
   620→    return { satisfiedBy: null, satisfiedByPm: null };
   621→  }
