   654→
   655→  /**
   656→   * Find suitable tracks for a PM based on type requirements.
   657→   */
   658→  async findSuitableTracks(
   659→    pmTypeId: string,
   660→    depotId: string | null,
   661→    targetDate: string,
   662→    durationDays: number
   663→  ): Promise<TrackAllocation[]> {
   664→    return this.traced('findSuitableTracks', async (span) => {
   665→      span.setAttribute('pm.typeId', pmTypeId);
   666→      span.setAttribute('pm.targetDate', targetDate);
   667→
   668→      // Get PM type requirements
   669→      const pmType = await this.db.query.pmTypes.findFirst({
   670→        where: eq(pmTypes.id, pmTypeId),
   671→      });
   672→
   673→      if (!pmType) {
   674→        throw new NotFoundError(`PM type not found: ${pmTypeId}`, {
   675→          entityType: 'pm_type',
   676→          entityId: pmTypeId,
   677→        });
   678→      }
   679→
   680→      // Get required capabilities for this PM type
   681→      const requiredCapabilities = await this.db.query.pmCapabilityRequirements.findMany({
   682→        where: eq(pmCapabilityRequirements.pmTypeId, pmTypeId),
   683→      });
   684→
   685→      const mandatoryCapabilities = requiredCapabilities
   686→        .filter(c => c.isMandatory)
   687→        .map(c => c.capability);
   688→
   689→      // Find tracks that match the track type
   690→      const trackConditions: SQL<unknown>[] = [
   691→        eq(tracks.trackType, pmType.trackType),
   692→        eq(tracks.active, true),
   693→      ];
   694→
   695→      if (depotId) {
   696→        trackConditions.push(eq(tracks.depotId, depotId));
   697→      }
   698→
   699→      const candidateTracks = await this.db.query.tracks.findMany({
   700→        where: and(...trackConditions),
   701→        with: {
   702→          depot: true,
   703→        },
   704→      });
   705→
   706→      // Check each track for capabilities and availability
   707→      const allocations: TrackAllocation[] = [];
   708→      const endDate = new Date(targetDate);
   709→      endDate.setDate(endDate.getDate() + durationDays - 1);
   710→      const endDateStr = endDate.toISOString().split('T')[0];
   711→
   712→      for (const track of candidateTracks) {
   713→        // Get track capabilities
   714→        const capabilities = await this.db.query.trackCapabilities.findMany({
   715→          where: and(
   716→            eq(trackCapabilities.trackId, track.id),
   717→            eq(trackCapabilities.isOperational, true)
   718→          ),
   719→        });
   720→
   721→        const trackCapabilitySet = new Set(capabilities.map(c => c.capability));
   722→
   723→        // Check mandatory capabilities
   724→        const missingCapabilities = mandatoryCapabilities.filter(
   725→          cap => !trackCapabilitySet.has(cap)
   726→        );
   727→
   728→        // Check availability (no conflicting PM)
   729→        const conflicts = await this.db.query.pmSchedule.findMany({
   730→          where: and(
   731→            eq(pmSchedule.assignedTrackId, track.id),
   732→            inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
   733→            isNull(pmSchedule.scenarioId),
   734→            sql`${pmSchedule.targetDate} <= ${endDateStr}`,
   735→            sql`DATE(${pmSchedule.targetDate}) + COALESCE(
   736→              (SELECT min_track_days FROM pm_types WHERE id = ${pmSchedule.pmTypeId}), 1
   737→            ) > ${targetDate}`
   738→          ),
   739→        });
   740→
   741→        if (conflicts.length === 0) {
   742→          allocations.push({
   743→            trackId: track.id,
   744→            trackNumber: track.trackNumber,
   745→            depotId: track.depotId,
   746→            depotCode: track.depot?.code ?? 'unknown',
   747→            trackType: track.trackType as TrackType,
   748→            startDate: targetDate,
   749→            endDate: endDateStr,
   750→            hasAllCapabilities: missingCapabilities.length === 0,
   751→            missingCapabilities,
   752→          });
   753→        }
   754→      }
   755→
   756→      // Sort by capability match (prefer tracks with all capabilities)
   757→      allocations.sort((a, b) => {
   758→        if (a.hasAllCapabilities && !b.hasAllCapabilities) return -1;
   759→        if (!a.hasAllCapabilities && b.hasAllCapabilities) return 1;
   760→        return a.missingCapabilities.length - b.missingCapabilities.length;
   761→      });
   762→
   763→      span.setAttribute('result.trackCount', allocations.length);
   764→      return allocations;
   765→    });
   766→  }
