   768→  /**
   769→   * Check for track conflicts.
   770→   */
   771→  async checkTrackConflict(
   772→    trackId: string,
   773→    targetDate: string,
   774→    durationDays: number,
   775→    excludePmId?: string
   776→  ): Promise<PmScheduleRecord | null> {
   777→    return this.traced('checkTrackConflict', async (span) => {
   778→      span.setAttribute('track.id', trackId);
   779→      span.setAttribute('pm.targetDate', targetDate);
   780→
   781→      const endDate = new Date(targetDate);
   782→      endDate.setDate(endDate.getDate() + durationDays - 1);
   783→      const endDateStr = endDate.toISOString().split('T')[0];
   784→
   785→      const conditions: SQL<unknown>[] = [
   786→        eq(pmSchedule.assignedTrackId, trackId),
   787→        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
   788→        isNull(pmSchedule.scenarioId),
   789→        sql`${pmSchedule.targetDate} <= ${endDateStr}`,
   790→        sql`DATE(${pmSchedule.targetDate}) + COALESCE(
   791→          (SELECT min_track_days FROM pm_types WHERE id = ${pmSchedule.pmTypeId}), 1
   792→        ) > ${targetDate}`,
   793→      ];
   794→
   795→      if (excludePmId) {
   796→        conditions.push(sql`${pmSchedule.id} != ${excludePmId}`);
   797→      }
   798→
   799→      const conflict = await this.db.query.pmSchedule.findFirst({
   800→        where: and(...conditions),
   801→      });
   802→
   803→      return conflict ?? null;
   804→    });
