   807→  // ===========================================================================
   808→  // Material Constraint Checking
   809→  // ===========================================================================
   810→
   811→  /**
   812→   * Check material availability for a PM.
   813→   *
   814→   * Material constraints:
   815→   * - Hard (14 days): BLOCKING parts must be available
   816→   * - Soft (90 days): Warning if parts unavailable
   817→   */
   818→  async checkMaterialAvailability(
   819→    pmTypeId: string,
   820→    depotId: string,
   821→    targetDate: string
   822→  ): Promise<MaterialConstraintResult> {
   823→    return this.traced('checkMaterialAvailability', async (span) => {
   824→      span.setAttribute('pm.typeId', pmTypeId);
   825→      span.setAttribute('depot.id', depotId);
   826→      span.setAttribute('pm.targetDate', targetDate);
   827→
   828→      // Get required materials for this PM type
   829→      const requirements = await this.db.query.pmMaterialRequirements.findMany({
   830→        where: eq(pmMaterialRequirements.pmTypeId, pmTypeId),
   831→      });
   832→
   833→      if (requirements.length === 0) {
   834→        return {
   835→          isBlocked: false,
   836→          hardConstraintViolations: [],
   837→          softConstraintWarnings: [],
   838→          totalMissingParts: 0,
   839→          reservations: [],
   840→        };
   841→      }
   842→
   843→      const today = new Date();
   844→      const pmDate = new Date(targetDate);
   845→      const daysUntilPm = Math.ceil((pmDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
   846→
   847→      const hardViolations: MaterialAvailability[] = [];
   848→      const softWarnings: MaterialAvailability[] = [];
   849→      const reservations: Array<{ partNumber: string; quantity: number; type: ReservationType }> = [];
   850→
   851→      for (const req of requirements) {
   852→        // Get inventory at the depot
   853→        const inventory = await this.db.query.inventoryPositions.findFirst({
   854→          where: and(
   855→            eq(inventoryPositions.depotId, depotId),
   856→            eq(inventoryPositions.partNumber, req.partNumber)
   857→          ),
   858→        });
   859→
   860→        const availableQty = inventory
   861→          ? (inventory.quantityOnHand ?? 0) - (inventory.quantityReserved ?? 0)
   862→          : 0;
   863→
   864→        const availability: MaterialAvailability = {
   865→          partNumber: req.partNumber,
   866→          partDescription: req.partDescription,
   867→          criticality: req.criticality as MaterialCriticality,
   868→          requiredQuantity: req.quantityPerPm,
   869→          availableQuantity: availableQty,
   870→          depotId,
   871→          isAvailable: availableQty >= req.quantityPerPm,
   872→          shortfall: Math.max(0, req.quantityPerPm - availableQty),
   873→          leadTimeDays: req.leadTimeDays ?? 14,
   874→          expectedAvailableDate: inventory?.nextDeliveryDate ?? null,
   875→        };
   876→
   877→        if (!availability.isAvailable) {
   878→          // Check if this is a hard or soft constraint violation
   879→          if (req.criticality === 'BLOCKING' && daysUntilPm <= HARD_MATERIAL_WINDOW_DAYS) {
   880→            hardViolations.push(availability);
   881→          } else if (daysUntilPm <= SOFT_MATERIAL_WINDOW_DAYS) {
   882→            softWarnings.push(availability);
   883→          }
   884→        }
   885→
   886→        // Create reservation record
   887→        if (availableQty >= req.quantityPerPm) {
   888→          reservations.push({
   889→            partNumber: req.partNumber,
   890→            quantity: req.quantityPerPm,
   891→            type: daysUntilPm <= HARD_MATERIAL_WINDOW_DAYS ? 'HARD' : 'SOFT',
   892→          });
   893→        }
   894→      }
   895→
   896→      const isBlocked = hardViolations.length > 0;
   897→
   898→      span.setAttribute('material.isBlocked', isBlocked);
   899→      span.setAttribute('material.hardViolations', hardViolations.length);
   900→      span.setAttribute('material.softWarnings', softWarnings.length);
   901→
   902→      return {
   903→        isBlocked,
   904→        hardConstraintViolations: hardViolations,
   905→        softConstraintWarnings: softWarnings,
   906→        totalMissingParts: hardViolations.length + softWarnings.length,
   907→        reservations,
   908→      };
   909→    });
   910→  }
