   972→
   973→  /**
   974→   * Schedule a new PM.
   975→   */
   976→  async schedulePm(request: SchedulePmRequest): Promise<PmScheduleRecord> {
   977→    return this.inTransaction('schedulePm', async (tx, span) => {
   978→      const {
   979→        trainId,
   980→        pmTypeId,
   981→        targetDate,
   982→        assignedDepotId,
   983→        assignedTrackId,
   984→        assignedShift,
   985→        notes,
   986→        createdBy,
   987→        skipMaterialCheck,
   988→        skipServiceDemandCheck,
   989→      } = request;
   990→
   991→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   992→      span.setAttribute('pm.typeId', pmTypeId);
   993→      span.setAttribute('pm.targetDate', targetDate);
   994→
   995→      // Get train
   996→      const train = await tx.query.trains.findFirst({
   997→        where: eq(trains.id, trainId),
   998→        with: { fleet: true, currentDepot: true },
   999→      });
  1000→
  1001→      if (!train) {
  1002→        throw new TrainNotFoundError(trainId);
  1003→      }
  1004→
  1005→      span.setAttribute(MmsAttributes.TRAIN_NUMBER, train.trainNumber);
  1006→
  1007→      // Get PM type
  1008→      const pmType = await tx.query.pmTypes.findFirst({
  1009→        where: eq(pmTypes.id, pmTypeId),
  1010→      });
  1011→
  1012→      if (!pmType) {
  1013→        throw new NotFoundError(`PM type not found: ${pmTypeId}`, {
  1014→          entityType: 'pm_type',
  1015→          entityId: pmTypeId,
  1016→        });
  1017→      }
  1018→
  1019→      // Calculate compliance window
  1020→      const dueResult = await this.calculateComplianceWindow(trainId, pmTypeId);
  1021→
  1022→      // Validate target date is within compliance window
  1023→      if (targetDate < dueResult.complianceWindow.startDate ||
  1024→          targetDate > dueResult.complianceWindow.endDate) {
  1025→        throw new ComplianceWindowError(
  1026→          `Target date ${targetDate} is outside compliance window [${dueResult.complianceWindow.startDate}, ${dueResult.complianceWindow.endDate}]`,
  1027→          {
  1028→            windowStart: new Date(dueResult.complianceWindow.startDate),
  1029→            windowEnd: new Date(dueResult.complianceWindow.endDate),
  1030→            targetDate: new Date(targetDate),
  1031→          }
  1032→        );
  1033→      }
  1034→
  1035→      // Check service demand (unless skipped)
  1036→      if (!skipServiceDemandCheck) {
  1037→        const { canSchedule, validation } = await this.serviceDemandService.canScheduleTrainForMaintenance(
  1038→          trainId,
  1039→          targetDate
  1040→        );
  1041→
  1042→        if (!canSchedule) {
  1043→          throw new ServiceDemandViolationError(
  1044→            validation.message,
  1045→            {
  1046→              fleetId: validation.fleetId,
  1047→              requiredTrains: validation.required,
  1048→              availableTrains: validation.availableTrains,
  1049→            }
  1050→          );
  1051→        }
  1052→      }
  1053→
  1054→      // Check unavailability
  1055→      const activeUnavailability = await this.unavailabilityService.getActiveEventsForTrain(trainId);
  1056→      const blockingEvent = activeUnavailability.find(e => e.blocksPmScheduling);
  1057→
  1058→      if (blockingEvent) {
  1059→        throw new BusinessRuleError(
  1060→          `Train ${train.trainNumber} has active unavailability blocking PM scheduling: ${blockingEvent.eventType}`,
  1061→          {
  1062→            rule: 'unavailability_blocks_pm',
  1063→            context: { eventId: blockingEvent.id, eventType: blockingEvent.eventType },
  1064→          }
  1065→        );
  1066→      }
  1067→
  1068→      // Determine depot
  1069→      const depotId = assignedDepotId ?? train.currentDepotId ?? train.homeDepotId;
  1070→      if (!depotId) {
  1071→        throw new ValidationError('No depot assigned and train has no current/home depot');
  1072→      }
  1073→
  1074→      // Check material availability (unless skipped)
  1075→      let materialResult: MaterialConstraintResult | null = null;
  1076→      if (!skipMaterialCheck) {
  1077→        materialResult = await this.checkMaterialAvailability(pmTypeId, depotId, targetDate);
  1078→
  1079→        if (materialResult.isBlocked) {
  1080→          const blockingParts = materialResult.hardConstraintViolations
  1081→            .map(v => v.partNumber)
  1082→            .join(', ');
  1083→
  1084→          throw new MaterialConstraintError(
  1085→            `Blocking materials not available: ${blockingParts}`,
  1086→            {
  1087→              partNumber: materialResult.hardConstraintViolations[0]?.partNumber,
  1088→              requiredQuantity: materialResult.hardConstraintViolations[0]?.requiredQuantity,
  1089→              availableQuantity: materialResult.hardConstraintViolations[0]?.availableQuantity,
  1090→            }
  1091→          );
  1092→        }
  1093→      }
  1094→
  1095→      // Find or validate track
  1096→      let trackId = assignedTrackId;
  1097→      if (!trackId) {
  1098→        const trackDuration = pmType.minTrackDays ?? 1;
  1099→        const suitableTracks = await this.findSuitableTracks(
  1100→          pmTypeId,
  1101→          depotId,
  1102→          targetDate,
  1103→          trackDuration
  1104→        );
  1105→
  1106→        if (suitableTracks.length > 0) {
  1107→          trackId = suitableTracks[0].trackId;
  1108→        }
  1109→      } else {
  1110→        // Validate provided track
  1111→        const conflict = await this.checkTrackConflict(
  1112→          trackId,
  1113→          targetDate,
  1114→          pmType.minTrackDays ?? 1
  1115→        );
  1116→
  1117→        if (conflict) {
  1118→          throw new TrackConflictError(
  1119→            `Track is already occupied on ${targetDate}`,
  1120→            {
  1121→              trackId,
  1122→              conflictingScheduleId: conflict.id,
  1123→            }
  1124→          );
  1125→        }
  1126→      }
  1127→
  1128→      // Estimate mileage at target date
  1129→      const dailyKm = await this.getAverageDailyKm(trainId);
  1130→      const today = new Date();
  1131→      const daysUntilTarget = Math.ceil(
  1132→        (new Date(targetDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
  1133→      );
  1134→      const targetMileageKm = (train.currentMileageKm ?? 0) + (daysUntilTarget * dailyKm);
  1135→
  1136→      // Create PM schedule record
  1137→      const pmData: NewPmScheduleRecord = {
  1138→        trainId,
  1139→        pmTypeId,
  1140→        targetDate,
  1141→        targetMileageKm: Math.round(targetMileageKm),
  1142→        status: 'SCHEDULED',
  1143→        constraintStart: dueResult.complianceWindow.startDate,
  1144→        constraintEnd: dueResult.complianceWindow.endDate,
  1145→        assignedDepotId: depotId,
  1146→        assignedTrackId: trackId ?? null,
  1147→        assignedHours: pmType.estimatedHours,
  1148→        assignedShift: assignedShift ?? null,
  1149→        createdBy: createdBy ?? null,
  1150→      };
  1151→
  1152→      const [created] = await tx.insert(pmSchedule).values(pmData).returning();
  1153→      span.setAttribute('pm.scheduleId', created.id);
  1154→
  1155→      // Create audit history record
  1156→      if (createdBy) {
  1157→        const historyRecord: NewPmScheduleHistory = {
  1158→          pmScheduleId: created.id,
  1159→          changeType: 'CREATED',
  1160→          newTargetDate: targetDate,
  1161→          newStatus: 'SCHEDULED',
  1162→          newAssignedTrackId: trackId ?? null,
  1163→          newAssignedHours: pmType.estimatedHours,
  1164→          changedBy: createdBy,
  1165→          changeReason: notes ?? 'PM scheduled',
  1166→          changeSource: 'USER',
  1167→        };
  1168→
  1169→        await tx.insert(pmScheduleHistory).values(historyRecord);
  1170→      }
  1171→
  1172→      // Create material reservations
  1173→      if (materialResult?.reservations && materialResult.reservations.length > 0) {
  1174→        for (const reservation of materialResult.reservations) {
  1175→          const inventory = await tx.query.inventoryPositions.findFirst({
  1176→            where: and(
  1177→              eq(inventoryPositions.depotId, depotId),
  1178→              eq(inventoryPositions.partNumber, reservation.partNumber)
  1179→            ),
  1180→          });
  1181→
  1182→          if (inventory) {
  1183→            await tx.insert(materialReservations).values({
  1184→              pmScheduleId: created.id,
  1185→              inventoryPositionId: inventory.id,
  1186→              partNumber: reservation.partNumber,
  1187→              quantityReserved: reservation.quantity,
  1188→              reservationType: reservation.type,
  1189→              reservedBy: createdBy ?? null,
  1190→              expiresAt: reservation.type === 'SOFT'
  1191→                ? new Date(Date.now() + 30 * 24 * 60 * 60 * 1000)
  1192→                : null,
  1193→            });
  1194→
  1195→            // Update inventory reserved quantity
  1196→            await tx
  1197→              .update(inventoryPositions)
  1198→              .set({
  1199→                quantityReserved: sql`${inventoryPositions.quantityReserved} + ${reservation.quantity}`,
  1200→              })
  1201→              .where(eq(inventoryPositions.id, inventory.id));
  1202→          }
  1203→        }
  1204→      }
  1205→
  1206→      this.log.info(
  1207→        {
  1208→          pmScheduleId: created.id,
  1209→          trainId,
  1210→          trainNumber: train.trainNumber,
  1211→          pmCode: pmType.pmCode,
  1212→          targetDate,
  1213→          trackId,
  1214→          depotId,
  1215→        },
  1216→        `PM scheduled: ${pmType.pmCode} for ${train.trainNumber} on ${targetDate}`
  1217→      );
  1218→
  1219→      return created;
  1220→    });
  1221→  }
