  1223→  /**
  1224→   * Move an existing PM to a new date.
  1225→   */
  1226→  async movePm(request: MovePmRequest): Promise<PmScheduleRecord> {
  1227→    return this.inTransaction('movePm', async (tx, span) => {
  1228→      const { pmScheduleId, newTargetDate, newTrackId, reason, movedBy } = request;
  1229→
  1230→      span.setAttribute('pm.scheduleId', pmScheduleId);
  1231→      span.setAttribute('pm.newTargetDate', newTargetDate);
  1232→
  1233→      // Get existing PM with relations
  1234→      const existingPm = await tx.query.pmSchedule.findFirst({
  1235→        where: eq(pmSchedule.id, pmScheduleId),
  1236→        with: {
  1237→          train: true,
  1238→          pmType: true,
  1239→          assignedTrack: true,
  1240→        },
  1241→      }) as PmWithDetails | null;
  1242→
  1243→      if (!existingPm) {
  1244→        throw new PmScheduleNotFoundError(pmScheduleId);
  1245→      }
  1246→
  1247→      // Check Maximo lock
  1248→      const lockStatus = await this.checkMaximoLock(pmScheduleId);
  1249→      if (lockStatus.isLocked) {
  1250→        throw new MaximoLockError(
  1251→          `PM cannot be moved: ${lockStatus.reason}`,
  1252→          {
  1253→            workOrderId: lockStatus.workOrderId ?? undefined,
  1254→            maximoStatus: lockStatus.maximoStatus ?? undefined,
  1255→          }
  1256→        );
  1257→      }
  1258→
  1259→      // Check status - only SCHEDULED can be moved
  1260→      if (existingPm.status !== 'SCHEDULED') {
  1261→        throw new BusinessRuleError(
  1262→          `PM cannot be moved: status is ${existingPm.status}`,
  1263→          {
  1264→            rule: 'pm_status_move',
  1265→            context: { currentStatus: existingPm.status },
  1266→          }
  1267→        );
  1268→      }
  1269→
  1270→      // Validate new date is within compliance window
  1271→      if (newTargetDate < existingPm.constraintStart ||
  1272→          newTargetDate > existingPm.constraintEnd) {
  1273→        throw new ComplianceWindowError(
  1274→          `New target date ${newTargetDate} is outside compliance window [${existingPm.constraintStart}, ${existingPm.constraintEnd}]`,
  1275→          {
  1276→            windowStart: new Date(existingPm.constraintStart),
  1277→            windowEnd: new Date(existingPm.constraintEnd),
  1278→            targetDate: new Date(newTargetDate),
  1279→          }
  1280→        );
  1281→      }
  1282→
  1283→      // Check service demand at new date
  1284→      const { canSchedule, validation } = await this.serviceDemandService.canScheduleTrainForMaintenance(
  1285→        existingPm.trainId,
  1286→        newTargetDate
  1287→      );
  1288→
  1289→      if (!canSchedule) {
  1290→        throw new ServiceDemandViolationError(
  1291→          validation.message,
  1292→          {
  1293→            fleetId: validation.fleetId,
  1294→            requiredTrains: validation.required,
  1295→            availableTrains: validation.availableTrains,
  1296→          }
  1297→        );
  1298→      }
  1299→
  1300→      // Handle track change
  1301→      let trackId = newTrackId ?? existingPm.assignedTrackId;
  1302→      if (trackId) {
  1303→        const conflict = await this.checkTrackConflict(
  1304→          trackId,
  1305→          newTargetDate,
  1306→          existingPm.pmType?.minTrackDays ?? 1,
  1307→          pmScheduleId
  1308→        );
  1309→
  1310→        if (conflict) {
  1311→          // Try to find alternative track
  1312→          if (!newTrackId) {
  1313→            const alternatives = await this.findSuitableTracks(
  1314→              existingPm.pmTypeId,
  1315→              existingPm.assignedDepotId,
  1316→              newTargetDate,
  1317→              existingPm.pmType?.minTrackDays ?? 1
  1318→            );
  1319→
  1320→            if (alternatives.length > 0) {
  1321→              trackId = alternatives[0].trackId;
  1322→            } else {
  1323→              trackId = null; // Clear track assignment
  1324→            }
  1325→          } else {
  1326→            throw new TrackConflictError(
  1327→              `Track is already occupied on ${newTargetDate}`,
  1328→              {
  1329→                trackId,
  1330→                conflictingScheduleId: conflict.id,
  1331→              }
  1332→            );
  1333→          }
  1334→        }
  1335→      }
  1336→
  1337→      // Calculate new target mileage
  1338→      const dailyKm = await this.getAverageDailyKm(existingPm.trainId);
  1339→      const today = new Date();
  1340→      const daysUntilTarget = Math.ceil(
  1341→        (new Date(newTargetDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
  1342→      );
  1343→      const currentMileage = existingPm.train?.currentMileageKm ?? 0;
  1344→      const newTargetMileageKm = currentMileage + (daysUntilTarget * dailyKm);
  1345→
  1346→      // Record old values for history
  1347→      const oldTargetDate = existingPm.targetDate;
  1348→      const oldTrackId = existingPm.assignedTrackId;
  1349→
  1350→      // Update PM schedule
  1351→      const [updated] = await tx
  1352→        .update(pmSchedule)
  1353→        .set({
  1354→          targetDate: newTargetDate,
  1355→          targetMileageKm: Math.round(newTargetMileageKm),
  1356→          assignedTrackId: trackId,
  1357→          updatedAt: new Date(),
  1358→        })
  1359→        .where(eq(pmSchedule.id, pmScheduleId))
  1360→        .returning();
  1361→
  1362→      // Create audit history record
  1363→      const historyRecord: NewPmScheduleHistory = {
  1364→        pmScheduleId,
  1365→        changeType: 'DATE_CHANGED',
  1366→        oldTargetDate,
  1367→        newTargetDate,
  1368→        oldAssignedTrackId: oldTrackId,
  1369→        newAssignedTrackId: trackId,
  1370→        changedBy: movedBy,
  1371→        changeReason: reason,
  1372→        changeSource: 'USER',
  1373→      };
  1374→
  1375→      await tx.insert(pmScheduleHistory).values(historyRecord);
  1376→
  1377→      const trainNumber = existingPm.train?.trainNumber ?? 'unknown';
  1378→      const pmCode = existingPm.pmType?.pmCode ?? 'unknown';
  1379→
  1380→      this.log.info(
  1381→        {
  1382→          pmScheduleId,
  1383→          trainNumber,
  1384→          pmCode,
  1385→          oldTargetDate,
  1386→          newTargetDate,
  1387→          reason,
  1388→          movedBy,
  1389→        },
  1390→        `PM moved: ${pmCode} for ${trainNumber} from ${oldTargetDate} to ${newTargetDate}`
  1391→      );
  1392→
  1393→      return updated;
  1394→    });
  1395→  }
